"use strict";parserFactory.register("mangakakalot.com",()=>new MangakakalotParser);class MangakakalotParser extends Parser{constructor(){super()}getChapterUrls(e){let r=e.querySelector("div#chapter");return Promise.resolve(util.hyperlinksToChapterList(r).reverse())}findContent(e){return e.querySelector("div#vungdoc")}extractTitleImpl(e){return e.querySelector("div.manga-info-top h1")}extractAuthor(e){let r=e.querySelector("ul.manga-info-text a[href*='search_author']");return null===r?super.extractAuthor(e):r.textContent}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.manga-info-pic")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("ul.manga-info-text, div#noidungm")]}}